import React from "react";
import "./Header.css";

export const HeaderComponent = () => {
  return (
    <header className="header-pasteleria">
      <div className="header-logo">
        <span className="logo-icon">🍰</span>
        <span className="logo-text">Dulce Tentación</span>
      </div>
      <nav className="header-nav">
        <ul className="nav-menu">
          {["Inicio", "Pasteles", "Postres", "Eventos", "Nosotros"].map(
            (item) => (
              <li key={item}>
                <a href="#" className={item === "Inicio" ? "active" : ""}>
                  {item}
                </a>
              </li>
            )
          )}
        </ul>
      </nav>
      <div className="header-actions">
        <button className="btn-cart">🛒</button>
        <button className="btn-contact">Contacto</button>
      </div>
    </header>
  );
};
